import{_ as t,o as a,c as i,ag as r}from"./chunks/framework.CnqOxlWO.js";const u=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/quickstart.md","filePath":"getting-started/quickstart.md","lastUpdated":1773376681000}'),o={name:"getting-started/quickstart.md"};function n(l,e,s,h,p,c){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>This page walks you through the first five minutes after installing ClawdSaber.</p><h2 id="the-quick-path" tabindex="-1">The Quick Path <a class="header-anchor" href="#the-quick-path" aria-label="Permalink to &quot;The Quick Path&quot;">​</a></h2><ol><li>Log in.</li><li>Complete the first-time setup wizard.</li><li>Create your first agent.</li><li>Pick a model for the agent.</li><li>Start chatting.</li></ol><p>Each step is explained below.</p><h2 id="step-1-log-in" tabindex="-1">Step 1: Log In <a class="header-anchor" href="#step-1-log-in" aria-label="Permalink to &quot;Step 1: Log In&quot;">​</a></h2><p>Open ClawdSaber. You will see the login screen.</p><ol><li>Enter your email address.</li><li>Click <strong>Send Magic Link</strong>.</li><li>Check your inbox for an email from ClawdSaber.</li><li>Click the link in the email, or copy and paste it into the app.</li></ol><p>If the link opens your browser instead of the app, copy the full URL and paste it into the input field on the login screen.</p><p>For more details, see <a href="/clawdsaber-docs/getting-started/login.html">Login &amp; Registration</a>.</p><h2 id="step-2-first-time-setup-wizard" tabindex="-1">Step 2: First-Time Setup Wizard <a class="header-anchor" href="#step-2-first-time-setup-wizard" aria-label="Permalink to &quot;Step 2: First-Time Setup Wizard&quot;">​</a></h2><p>After your first login, the setup wizard appears. It has three steps:</p><h3 id="welcome" tabindex="-1">Welcome <a class="header-anchor" href="#welcome" aria-label="Permalink to &quot;Welcome&quot;">​</a></h3><p>Choose your preferred language (English, Chinese, or Japanese) and review a brief introduction to the app&#39;s key features.</p><h3 id="environment-check" tabindex="-1">Environment Check <a class="header-anchor" href="#environment-check" aria-label="Permalink to &quot;Environment Check&quot;">​</a></h3><p>The app verifies that the required runtime components are available:</p><ul><li><strong>OpenClaw</strong> — the backend engine that powers agents</li><li><strong>Gateway</strong> — the local service that routes messages between you and your agents</li></ul><p>If everything passes, you will see green checkmarks. If something fails, follow the on-screen instructions to resolve it.</p><h3 id="complete" tabindex="-1">Complete <a class="header-anchor" href="#complete" aria-label="Permalink to &quot;Complete&quot;">​</a></h3><p>A confirmation screen with links to the template library, agent marketplace, and settings. Click any of them to continue, or go straight to the main page.</p><p>The setup wizard only runs once. After completion, the app opens directly to the chat page on future launches.</p><h2 id="step-3-create-your-first-agent" tabindex="-1">Step 3: Create Your First Agent <a class="header-anchor" href="#step-3-create-your-first-agent" aria-label="Permalink to &quot;Step 3: Create Your First Agent&quot;">​</a></h2><p>You can create an agent from three places:</p><ul><li><strong>Template Library</strong> — Use a built-in or downloaded template. Best for getting started quickly.</li><li><strong>Agent Market</strong> — Browse community-contributed templates, download one, then create an agent from it.</li><li><strong>Sidebar &quot;+&quot; Button</strong> — A shortcut that opens the template picker.</li></ul><h3 id="using-a-built-in-template" tabindex="-1">Using a Built-In Template <a class="header-anchor" href="#using-a-built-in-template" aria-label="Permalink to &quot;Using a Built-In Template&quot;">​</a></h3><ol><li>Open the <strong>Templates</strong> page from the sidebar.</li><li>Pick a template from the <strong>Built-in</strong> section.</li><li>Click <strong>Create Agent</strong>.</li><li>Enter a name for your agent.</li><li>Confirm.</li></ol><p>The agent appears in the sidebar immediately.</p><h2 id="step-4-pick-a-model" tabindex="-1">Step 4: Pick a Model <a class="header-anchor" href="#step-4-pick-a-model" aria-label="Permalink to &quot;Step 4: Pick a Model&quot;">​</a></h2><p>A newly created agent does not have a model assigned yet. Without a model, it cannot respond to messages.</p><ol><li>In the sidebar, hover over your new agent and click the <strong>Settings</strong> icon.</li><li>Go to the <strong>Model</strong> tab.</li><li>Click <strong>Pick Platform Model</strong>.</li><li>Select a model from the list. The dialog shows pricing information and a brief description for each model.</li><li>Confirm your selection.</li></ol><p>The model is now assigned. You can change it at any time.</p><h2 id="step-5-start-chatting" tabindex="-1">Step 5: Start Chatting <a class="header-anchor" href="#step-5-start-chatting" aria-label="Permalink to &quot;Step 5: Start Chatting&quot;">​</a></h2><ol><li>Click the agent in the sidebar to switch to it.</li><li>Type a message in the input area at the bottom.</li><li>Press <strong>Enter</strong> to send.</li></ol><p>The agent streams its response in real time. You can stop generation at any time by clicking the <strong>Stop</strong> button.</p><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The shortest path from install to first conversation:</p><ol><li>Log in with email magic link.</li><li>Finish the 3-step setup wizard.</li><li>Create an agent from a built-in template.</li><li>Assign a platform model.</li><li>Send your first message.</li></ol><p>If the agent does not respond, check the <a href="/clawdsaber-docs/settings/faq.html">FAQ</a>.</p>',38)])])}const g=t(o,[["render",n]]);export{u as __pageData,g as default};
